output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?capital ?capitalLabel ?festival ?festivalLabel WHERE {
  ?country wdt:P30 wd:Q46 ; wdt:P36 ?capital .
  ?capital wdt:P31 wd:Q515 .
  ?festival wdt:P31 wd:Q132241 ; wdt:P276 ?capital .
  OPTIONAL {
    ?capital rdfs:label ?capitalLabel .
    FILTER(LANG(?capitalLabel) = "en")
  }
  OPTIONAL {
    ?festival rdfs:label ?festivalLabel .
    FILTER(LANG(?festivalLabel) = "en")
  }
}

